"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[918],{4323:e=>{e.exports=JSON.parse('{"functions":[{"name":"new","desc":"Creates a curve through the given control points. Points are sorted by x on\\nconstruction; x values must be distinct.","params":[{"name":"points","desc":"At least two control points.","lua_type":"{Vector2}"}],"returns":[{"desc":"","lua_type":"Curve"}],"function_type":"static","source":{"line":47,"path":"src/Curve.luau"}},{"name":"evaluate","desc":"Evaluates the curve at `x`. Inputs outside the control point domain clamp\\nto the first or last point\'s value.","params":[{"name":"x","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"number"}],"function_type":"method","source":{"line":132,"path":"src/Curve.luau"}},{"name":"evaluateWithDerivative","desc":"Evaluates the curve at `x` along with its derivative `dy/dx` \u2014 the local\\nslope of the spline, with no extra evaluations. Useful for chain-ruling\\nslope through a curve-shaped value (e.g. terrain steepened by a response\\ncurve) without resampling the underlying field. Outside the control point\\ndomain the curve is constant, so the derivative is 0 there.","params":[{"name":"x","desc":"","lua_type":"number"}],"returns":[{"desc":"y","lua_type":"number"},{"desc":"dy/dx","lua_type":"number"}],"function_type":"method","source":{"line":182,"path":"src/Curve.luau"}},{"name":"map","desc":"Evaluates the curve over a whole array in one call.","params":[{"name":"values","desc":"","lua_type":"{number}"}],"returns":[{"desc":"","lua_type":"{number}"}],"function_type":"method","source":{"line":237,"path":"src/Curve.luau"}},{"name":"domain","desc":"Returns the x extent covered by the control points.","params":[],"returns":[{"desc":"Smallest control point x.","lua_type":"number"},{"desc":"Largest control point x.","lua_type":"number"}],"function_type":"method","source":{"line":254,"path":"src/Curve.luau"}},{"name":"range","desc":"Returns the output extent of the curve. Because the spline is monotone\\nbetween control points, this is exactly the min and max control point y.","params":[],"returns":[{"desc":"Smallest output value.","lua_type":"number"},{"desc":"Largest output value.","lua_type":"number"}],"function_type":"method","source":{"line":267,"path":"src/Curve.luau"}}],"properties":[],"types":[],"name":"Curve","desc":"A response curve: control points interpolated with a monotone cubic Hermite\\nspline (Fritsch\u2013Carlson), evaluated as `y = curve:evaluate(x)`. The spline\\nnever overshoots its control points, which makes it safe for remapping\\nnoise into ranges like [0, 1] \u2014 shaping terrain falloff, biome thresholds,\\nspawn weights, or any other value.\\n\\n```lua\\nlocal falloff = Atlas.Curve.new({\\n\\tVector2.new(0, 0),\\n\\tVector2.new(0.4, 0.1),\\n\\tVector2.new(0.7, 0.8),\\n\\tVector2.new(1, 1),\\n})\\nlocal height = falloff:evaluate(noiseValue * 0.5 + 0.5)\\n```","source":{"line":24,"path":"src/Curve.luau"}}')}}]);